import React, { useEffect, useRef, useState } from 'react';
import {
  Stage,
  Layer,
  Group,
  Image as KonvaImage,
  Rect,
  Line,
  Circle,
  Ellipse,
  Transformer,
  Arrow,
} from 'react-konva';
import './AnnotationCanvas.css';

export default function AnnotationCanvas({
  fileUrl,
  annotations,
  onAnnotationsChange,
  selectedTool,
  scale,
  onWheelZoom,
  activeLabelColor,
  onFinishShape,
}) {
  const stageRef = useRef(null);
  const containerRef = useRef(null);

  const rectRefs = useRef([]);
  const ellipseRefs = useRef([]);
  const transformerRef = useRef(null);

  const [dims, setDims] = useState({ width: 0, height: 0 });
  const [konvaImg, setKonvaImg] = useState(null);
  const [imagePos, setImagePos] = useState({ x: 0, y: 0 });

  const [selectedShapeIndex, setSelectedShapeIndex] = useState(null);

  const [newBox, setNewBox] = useState(null);
  const [tempPoints, setTempPoints] = useState([]);
  const [drawingPolygon, setDrawingPolygon] = useState(false);
  const [newEllipse, setNewEllipse] = useState(null);

  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current) {
        setDims({
          width: containerRef.current.offsetWidth,
          height: containerRef.current.offsetHeight,
        });
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    if (!fileUrl) return;
    const img = new Image();
    img.src = fileUrl;
    img.onload = () => setKonvaImg(img);
  }, [fileUrl]);

  const flattenPoints = (pts) => pts.flatMap((p) => [p.x, p.y]);

  const getGroupPos = (evt) => {
    const group = stageRef.current?.findOne('#anno-group');
    return group?.getRelativePointerPosition() || null;
  };

  const renderBackgroundImage = () =>
    konvaImg && (
      <KonvaImage
        image={konvaImg}
        width={konvaImg.width}
        height={konvaImg.height}
        x={imagePos.x}
        y={imagePos.y}
        draggable={false}
      />
    );

  const handleMouseDown = (evt) => {
    const pos = getGroupPos(evt);
    if (!pos) return;

    if (selectedTool === 'bbox') {
      setNewBox({ x: pos.x, y: pos.y, width: 0, height: 0 });
    } else if (selectedTool === 'polygon') {
      setTempPoints([...tempPoints, pos]);
      setDrawingPolygon(true);
    } else if (selectedTool === 'ellipse') {
      setNewEllipse({ x: pos.x, y: pos.y, radiusX: 0, radiusY: 0 });
    }
  };

  const handleMouseMove = (evt) => {
    if (selectedTool === 'bbox' && newBox) {
      const pos = getGroupPos(evt);
      if (pos) setNewBox({ ...newBox, width: pos.x - newBox.x, height: pos.y - newBox.y });
    } else if (selectedTool === 'ellipse' && newEllipse) {
      const pos = getGroupPos(evt);
      if (pos)
        setNewEllipse({
          ...newEllipse,
          radiusX: Math.abs(pos.x - newEllipse.x),
          radiusY: Math.abs(pos.y - newEllipse.y),
        });
    }
  };

  const handleMouseUp = () => {
    if (selectedTool === 'bbox' && newBox) {
      onAnnotationsChange([...annotations, { ...newBox, type: 'bbox', label: '' }]);
      setNewBox(null);
      onFinishShape();
    } else if (selectedTool === 'ellipse' && newEllipse) {
      onAnnotationsChange([...annotations, { ...newEllipse, type: 'ellipse', label: '' }]);
      setNewEllipse(null);
      onFinishShape();
    }
  };

  const finalizePolygon = () => {
    if (tempPoints.length >= 3) {
      onAnnotationsChange([...annotations, { type: 'polygon', points: tempPoints, label: '' }]);
    }
    setTempPoints([]);
    setDrawingPolygon(false);
    onFinishShape();
  };

  const renderAnnotations = () =>
    annotations.map((ann, i) => {
      if (ann.type === 'bbox') {
        return (
          <Rect
            key={i}
            ref={(node) => (rectRefs.current[i] = node)}
            x={ann.x}
            y={ann.y}
            width={ann.width}
            height={ann.height}
            fill={`${activeLabelColor}55`}
            stroke={activeLabelColor}
            strokeWidth={2 / scale}
            draggable
            onDragEnd={(e) => {
              const { x, y } = e.target.position();
              const updated = [...annotations];
              updated[i] = { ...ann, x, y };
              onAnnotationsChange(updated);
            }}
            onTransformEnd={(e) => {
              const node = e.target;
              const width = node.width() * node.scaleX();
              const height = node.height() * node.scaleY();
              const { x, y } = node.position();
              node.scaleX(1);
              node.scaleY(1);
              const updated = [...annotations];
              updated[i] = { ...ann, x, y, width, height };
              onAnnotationsChange(updated);
            }}
          />
        );
      } else if (ann.type === 'polygon') {
        return (
          <Line
            key={i}
            points={flattenPoints(ann.points)}
            fill={`${activeLabelColor}55`}
            stroke={activeLabelColor}
            strokeWidth={2 / scale}
            closed
          />
        );
      } else if (ann.type === 'ellipse') {
        return (
          <Ellipse
            key={i}
            ref={(node) => (ellipseRefs.current[i] = node)}
            x={ann.x}
            y={ann.y}
            radiusX={ann.radiusX}
            radiusY={ann.radiusY}
            fill={`${activeLabelColor}55`}
            stroke={activeLabelColor}
            strokeWidth={2 / scale}
            draggable
            onDragEnd={(e) => {
              const { x, y } = e.target.position();
              const updated = [...annotations];
              updated[i] = { ...ann, x, y };
              onAnnotationsChange(updated);
            }}
          />
        );
      }
      return null;
    });

  return (
    <div className="canvas-container" ref={containerRef}>
      <Stage
        ref={stageRef}
        width={dims.width}
        height={dims.height}
        scaleX={scale}
        scaleY={scale}
        onWheel={(evt) => {
          evt.evt.preventDefault();
          onWheelZoom(evt.evt.deltaY);
        }}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={() => {
          if (drawingPolygon) finalizePolygon();
        }}
      >
        <Layer>{renderBackgroundImage()}</Layer>
        <Layer>
          <Group id="anno-group">{renderAnnotations()}</Group>
        </Layer>
      </Stage>
    </div>
  );
}
